const fs = require('fs');
const path = require('path');
const os = require('os');
const crypto = require('crypto');
const readline = require('readline');
const vm = require('vm');
const { execFile } = require('child_process');

const CONFIG = {
  model: process.env.LLM_MODEL || 'gpt-4.1-mini',
  apiKey: process.env.OPENAI_API_KEY || '',
  apiBaseUrl: process.env.OPENAI_BASE_URL || 'https://api.openai.com/v1',
  workingDir: process.env.CODEGEN_WORKDIR || path.join(process.cwd(), '.codegen-runs'),
  maxOutputChars: Number(process.env.MAX_OUTPUT_CHARS || 120000),
  timeoutMs: Number(process.env.EXEC_TIMEOUT_MS || 15000),
  maxStdoutChars: Number(process.env.MAX_STDOUT_CHARS || 20000),
  allowFileSystem: process.env.ALLOW_FS === 'true',
  allowNetwork: process.env.ALLOW_NETWORK === 'true'
};

if (!fs.existsSync(CONFIG.workingDir)) fs.mkdirSync(CONFIG.workingDir, { recursive: true });

function log(...args) {
  process.stdout.write(args.map(a => typeof a === 'string' ? a : JSON.stringify(a, null, 2)).join(' ') + '\n');
}

function readStdin() {
  return new Promise(resolve => {
    let data = '';
    process.stdin.setEncoding('utf8');
    process.stdin.on('data', chunk => data += chunk);
    process.stdin.on('end', () => resolve(data.trim()));
    process.stdin.resume();
  });
}

async function promptUser(question) {
  const rl = readline.createInterface({ input: process.stdin, output: process.stdout });
  return new Promise(resolve => rl.question(question, answer => {
    rl.close();
    resolve(answer.trim());
  }));
}

async function callLLM(description, context = {}) {
  if (!CONFIG.apiKey) {
    throw new Error('Missing OPENAI_API_KEY');
  }

  const system = [
    'You are an expert Node.js code generator for a no-code automation platform.',
    'Return ONLY valid JavaScript code.',
    'Do not include markdown, comments are allowed.',
    'Prefer a single self-contained async function named main if possible.',
    'The generated code will be executed in a sandboxed Node.js environment.',
    'Avoid using dangerous operations unless explicitly requested.',
    'If external packages are required, use only built-in Node.js modules.'
  ].join(' ');

  const user = [
    'User request:',
    description,
    '',
    'Execution context:',
    JSON.stringify(context)
  ].join('\n');

  const payload = {
    model: CONFIG.model,
    messages: [
      { role: 'system', content: system },
      { role: 'user', content: user }
    ],
    temperature: 0.2
  };

  const res = await fetch(`${CONFIG.apiBaseUrl.replace(/\/$/, '')}/chat/completions`, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${CONFIG.apiKey}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify(payload)
  });

  if (!res.ok) {
    const text = await res.text().catch(() => '');
    throw new Error(`LLM request failed: ${res.status} ${res.statusText} ${text}`.trim());
  }

  const json = await res.json();
  const content = json?.choices?.[0]?.message?.content || '';
  return content.trim().slice(0, CONFIG.maxOutputChars);
}

function sanitizeCode(code) {
  let out = String(code || '').trim();
  out = out.replace(/^```(?:javascript|js|node)?\s*/i, '').replace(/```$/i, '').trim();
  return out;
}

function extractMain(code) {
  const cleaned = sanitizeCode(code);
  if (/^\s*async\s+function\s+main\s*\(/m.test(cleaned) || /^\s*function\s+main\s*\(/m.test(cleaned)) return cleaned;
  return `${cleaned}\n\nmodule.exports = typeof main === 'function' ? main : async function main() { return undefined; };`;
}

function createSandbox() {
  const sandbox = {
    console,
    process: {
      env: { ...process.env },
      argv: [],
      cwd: () => process.cwd(),
      platform: process.platform,
      version: process.version,
      nextTick: process.nextTick.bind(process)
    },
    Buffer,
    setTimeout,
    clearTimeout,
    setInterval,
    clearInterval,
    queueMicrotask,
    TextEncoder,
    TextDecoder,
    URL,
    URLSearchParams,
    crypto,
    require: (mod) => {
      const allowed = new Set(['fs', 'path', 'os', 'url', 'util', 'crypto', 'stream', 'events', 'zlib', 'http', 'https', 'net', 'tls', 'querystring', 'child_process']);
      if (!allowed.has(mod)) throw new Error(`Module not allowed: ${mod}`);
      if (!CONFIG.allowFileSystem && mod === 'fs') throw new Error('Filesystem access disabled');
      if (!CONFIG.allowNetwork && ['http', 'https', 'net', 'tls'].includes(mod)) throw new Error('Network access disabled');
      return require(mod);
    },
    module: { exports: {} },
    exports: {}
  };
  sandbox.global = sandbox;
  sandbox.globalThis = sandbox;
  return sandbox;
}

async function executeGeneratedCode(code, input = {}) {
  const wrapped = extractMain(code);
  const sandbox = createSandbox();
  const script = new vm.Script(wrapped, { filename: 'generated.js', displayErrors: true });
  const context = vm.createContext(sandbox, { codeGeneration: { strings: true, wasm: false } });
  script.runInContext(context, { timeout: CONFIG.timeoutMs });

  let fn = context.module.exports;
  if (typeof fn !== 'function') {
    if (typeof context.main === 'function') fn = context.main;
    else throw new Error('Generated code did not export a function');
  }

  const result = await Promise.race([
    Promise.resolve().then(() => fn(input)),
    new Promise((_, reject) => setTimeout(() => reject(new Error('Execution timed out')), CONFIG.timeoutMs))
  ]);

  return result;
}

async function saveRun(description, code, result, error) {
  const id = crypto.randomUUID();
  const dir = path.join(CONFIG.workingDir, id);
  fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(path.join(dir, 'description.txt'), description, 'utf8');
  fs.writeFileSync(path.join(dir, 'generated.js'), code, 'utf8');
  fs.writeFileSync(path.join(dir, 'result.json'), JSON.stringify({ result, error: error ? String(error.stack || error.message || error) : null }, null, 2), 'utf8');
  return id;
}

async function main() {
  const inputArg = process.argv.slice(2).join(' ').trim();
  const description = inputArg || (await readStdin()) || (await promptUser('Describe the automation: '));

  if (!description) {
    throw new Error('No description provided');
  }

  const context = {
    platform: 'node-no-code-automation',
    allowedBuiltins: ['fs', 'path', 'os', 'url', 'util', 'crypto', 'stream', 'events', 'zlib', 'http', 'https'],
    instruction: 'Generate code that exports an async main(input) function or defines main().'
  };

  const generated = await callLLM(description, context);
  const code = sanitizeCode(generated);
  const result = await executeGeneratedCode(code, { description, timestamp: new Date().toISOString() }).catch(async (error) => {
    const id = await saveRun(description, code, null, error);
    throw Object.assign(error, { runId: id, generatedCode: code });
  });

  const runId = await saveRun(description, code, result, null);
  const output = {
    runId,
    generatedCode: code,
    result
  };

  log(JSON.stringify(output, null, 2));
}

main().catch(err => {
  const payload = {
    error: String(err.message || err),
    stack: err.stack || null,
    runId: err.runId || null,
    generatedCode: err.generatedCode || null
  };
  process.stderr.write(JSON.stringify(payload, null, 2) + '\n');
  process.exitCode = 1;
});